var limits = JSON.parse(metadata.shared_limits);
var telemetry_keys = JSON.parse(metadata
    .shared_telemetry_keys);

if (Object.keys(limits).length != telemetry_keys.length) {
    throw Error("Not enough data.");
}
for (var key in limits) {
    if (!msg.hasOwnProperty(key)) {
        throw Error("Missing telemetry for key: " + key);
    }
}

var outOfLimit = {};

function arrayIncludes(arr, val) {
    if (!arr) return false;
    if (Array.isArray(arr)) {
        for (var i = 0; i < arr.length; i++) {
            if (arr[i].toLowerCase() === val.toLowerCase())
                return true;
        }
        return false;
    } else if (typeof arr === "object") {
        for (var k in arr) {
            if (
                arr.hasOwnProperty(k) &&
                arr[k].toLowerCase() === val.toLowerCase()
            ) return true;
        }
        return false;
    }
    return false;
}

telemetry_keys.forEach(function(key) {
    var rule = limits[key];
    var value = msg[key];

    if (value == null || rule == null) return;

    var violated = false;

    if (rule.minimum != null && typeof value ===
        "number" && value < rule.minimum) {
        violated = true;
    }
    if (rule.maximum != null && typeof value ===
        "number" && value > rule.maximum) {
        violated = true;
    }
    if (rule.equal != null && !arrayIncludes(rule
            .equal, value)) {
        violated = true;
    }
    if (rule.not_equal != null && arrayIncludes(rule
            .not_equal, value)) {
        violated = true;
    }

    if (violated) {
        outOfLimit[key] = value;
    }
});

if (Object.keys(outOfLimit).length === 0) {
    throw new Error("No telemetry values out of limit.");
}


var returnObject = {
    tenantId: metadata.tenant_id,
    deviceId: metadata.originatorId,
    data: outOfLimit
};

return {
    msg: returnObject,
    metadata: metadata,
    msgType: msgType
};
